        return RuleOverlapResult {
            metric: RuleOverlapSummary::unavailable(format!(
                "failed to scan rule store: {error}"
            )),
            findings: Vec::new(),
        };
    }

    let rules = match store.list(&rule_api::RuleFilter::default(), None) {
        Ok(items) => items,
        Err(error) => {
            return RuleOverlapResult {
                metric: RuleOverlapSummary::unavailable(format!(
